mapper.select:
SELECT qw.warn_id AS warnId, qw.selection_id AS selectionId, qw.teacher_id AS teacherId, u_t.real_name AS teacherName, qw.student_id AS studentId, u_s.real_name AS studentName, u_s.student_no AS studentNo, ps.campus_name AS campusName, CASE WHEN ps.is_custom_topic = 1 THEN ps.custom_topic_name ELSE pt.topic_name END AS topicName, qw.warn_level AS warnLevel, qw.warn_type AS warnType, qw.reason, qw.status, qw.handler_id AS handlerId, u_h.real_name AS handlerName, qw.handle_comment AS handleComment, qw.handle_time AS handleTime, qw.academic_year AS academicYear, DATE_FORMAT(qw.create_time, '%Y-%m-%d %H:%i:%s') AS createTime FROM quality_warning qw LEFT JOIN sys_user u_t ON qw.teacher_id = u_t.user_id LEFT JOIN sys_user u_s ON qw.student_id = u_s.user_id LEFT JOIN project_selection ps ON qw.selection_id = ps.selection_id LEFT JOIN project_topic pt ON ps.topic_id = pt.topic_id LEFT JOIN sys_user u_h ON qw.handler_id = u_h.user_id
qw.is_deleted = 0
AND ps.campus_name LIKE CONCAT('%', #{campusName}, '%')
AND qw.academic_year = #{academicYear}
AND qw.warn_type = #{warnType}
AND qw.warn_level = #{warnLevel}
AND qw.status = #{status}
AND (u_t.real_name LIKE CONCAT('%', #{keyword}, '%') OR u_s.real_name LIKE CONCAT('%', #{keyword}, '%') OR u_s.student_no LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY qw.create_time DESC

SELECT qw.warn_id AS warnId, qw.selection_id AS selectionId, qw.teacher_id AS teacherId, u_t.real_name AS teacherName, qw.student_id AS studentId, u_s.real_name AS studentName, u_s.student_no AS studentNo, ps.campus_name AS campusName, CASE WHEN ps.is_custom_topic = 1 THEN ps.custom_topic_name ELSE pt.topic_name END AS topicName, qw.warn_level AS warnLevel, qw.warn_type AS warnType, qw.reason, qw.status, qw.handler_id AS handlerId, u_h.real_name AS handlerName, qw.handle_comment AS handleComment, qw.handle_time AS handleTime, qw.academic_year AS academicYear, DATE_FORMAT(qw.create_time, '%Y-%m-%d %H:%i:%s') AS createTime FROM quality_warning qw LEFT JOIN sys_user u_t ON qw.teacher_id = u_t.user_id LEFT JOIN sys_user u_s ON qw.student_id = u_s.user_id LEFT JOIN project_selection ps ON qw.selection_id = ps.selection_id LEFT JOIN project_topic pt ON ps.topic_id = pt.topic_id LEFT JOIN sys_user u_h ON qw.handler_id = u_h.user_id
qw.is_deleted = 0
AND qw.teacher_id = #{teacherId}
AND qw.academic_year = #{academicYear}
AND qw.warn_type = #{warnType}
AND qw.warn_level = #{warnLevel}
AND qw.status = #{status}
ORDER BY qw.create_time DESC
